INSERT INTO product
(menu, code, name, coname, price, opt1, opt2, contents, status, regday, icon_new, icon_hit, icon_sale, discount, image1, image2, image3)
VALUES
(1, 'BG190-001', '[2025new] 1번 스킨케어 SET', '비그룸', 54300, 0, 0, '지성 피부와 피지 고민을 위한 남성 스킨케어 세트입니다. 토너와 케어 제품을 함께 구성해 데일리 루틴으로 사용하기 좋습니다.', 1, CURDATE(), 1, 1, 0, 0, '', '', ''),
(1, 'BG190-002', '[2025new] 2번 스킨케어 SET', '비그룸', 49900, 0, 0, '복합성 및 수부지 피부를 위한 밸런스형 스킨케어 세트입니다. 번들거림과 속건조를 함께 관리하는 데 초점을 둔 구성입니다.', 1, CURDATE(), 1, 1, 0, 0, '', '', ''),
(1, 'BG190-003', '[2025new] 3번 스킨케어 SET', '비그룸', 51600, 0, 0, '건조함이 느껴지는 피부를 위한 보습 중심 스킨케어 세트입니다. 촉촉한 마무리감과 피부 컨디션 케어에 적합합니다.', 1, CURDATE(), 1, 1, 0, 0, '', '', ''),
(1, 'BG190-004', '[트루션] 센시톨로지 더마 크림 80ml', '트루션', 20500, 0, 0, '민감하고 건조한 피부에 사용하기 좋은 진정 보습 크림입니다. 피부 장벽 케어가 필요한 날 데일리 크림으로 추천합니다.', 1, CURDATE(), 0, 1, 0, 0, '', '', ''),
(5, 'BG190-005', '[복합성,수부지] 에스네이처 아쿠아 라이스 약산성 클렌징폼 대용량 207ml', '에스네이처', 16500, 0, 0, '약산성 포뮬러의 대용량 클렌징폼입니다. 수부지와 복합성 피부가 부담 없이 매일 사용하기 좋은 세안 제품입니다.', 1, CURDATE(), 0, 1, 0, 0, '', '', ''),
(1, 'BG190-006', '[웰라쥬] 리얼 히알루로닉 100 토너 200ml', 'wellage', 13500, 0, 0, '히알루론산 성분으로 세안 후 피부에 수분감을 더해주는 토너입니다. 가볍게 흡수되는 데일리 수분 토너입니다.', 1, CURDATE(), 0, 1, 0, 0, '', '', ''),
(1, 'BG190-007', '[에스네이처] 아쿠아 오아시스 수분 젤크림 80ml', '에스네이처', 19900, 0, 0, '끈적임을 줄이고 산뜻한 수분감을 주는 젤 타입 크림입니다. 유분 부담 없이 보습을 채우고 싶을 때 좋습니다.', 1, CURDATE(), 0, 1, 0, 0, '', '', ''),
(1, 'BG190-008', '[키니드] 히알루비타 앰플 50ml', '키니드', 15900, 0, 0, '수분과 생기 케어를 함께 노린 앰플입니다. 토너 다음 단계에서 피부 컨디션을 정돈하는 데 사용하기 좋습니다.', 1, CURDATE(), 0, 0, 0, 0, '', '', ''),
(1, 'BG190-009', '[라운드랩] 약콩 판테놀 토너 250ml', '라운드랩', 13900, 0, 0, '약콩과 판테놀 컨셉의 토너입니다. 세안 후 건조한 피부에 편안한 수분감을 더해주는 기초 제품입니다.', 1, CURDATE(), 0, 0, 0, 0, '', '', ''),
(7, 'BG190-010', '[B.WEEK][그라펜] 메가홀드 스프레이 250ml + 100ml', '그라펜', 19900, 0, 0, '강한 고정력이 필요한 헤어 스타일링용 스프레이 구성입니다. 외출 전 헤어 스타일을 오래 유지하고 싶을 때 적합합니다.', 1, CURDATE(), 1, 1, 1, 0, '', '', ''),
(1, 'BG190-011', '[B.WEEK] [DMCK] 클린 아크 앰플 30ml 1+1', '디엠씨케이컴퍼니', 38900, 0, 0, '트러블과 진정 고민 피부를 위한 앰플 1+1 구성입니다. 집중 케어가 필요한 부위에 사용하기 좋은 제품입니다.', 1, CURDATE(), 1, 1, 1, 0, '', '', ''),
(7, 'BG190-012', '[B.WEEK][에이킨(AEKIN)] 쿨 밸런스 쉐이빙 젤 250ml 1+1', '에이킨(AEKIN)', 16800, 0, 0, '면도 시 피부 마찰을 줄여주는 쿨링 쉐이빙 젤 1+1 구성입니다. 산뜻한 사용감으로 데일리 면도에 잘 맞습니다.', 1, CURDATE(), 1, 1, 1, 0, '', '', ''),
(7, 'BG190-013', '[에이킨(AEKIN)] 쿨 밸런스 쉐이빙 젤 250ml', '에이킨(AEKIN)', 9900, 0, 0, '가볍고 시원한 사용감의 쉐이빙 젤입니다. 면도 전 피부를 부드럽게 정돈해 깔끔한 면도감을 돕습니다.', 1, CURDATE(), 0, 0, 0, 0, '', '', ''),
(3, 'BG190-014', '[각질관리] 라운드랩 1025 독도 필링젤 대용량 155ml', '라운드랩', 9900, 0, 0, '피부 표면의 묵은 각질을 관리하는 필링젤입니다. 대용량으로 얼굴과 바디의 거친 부위를 관리하기 좋습니다.', 1, CURDATE(), 0, 0, 0, 0, '', '', ''),
(1, 'BG190-015', '[유이크] 바이옴 레미디 피에이치 밸런싱 토너 300ml', '유이크', 15600, 0, 0, '피부 pH 밸런스와 수분 정돈을 위한 토너입니다. 넉넉한 용량으로 아침저녁 데일리 케어에 사용하기 좋습니다.', 1, CURDATE(), 0, 0, 0, 0, '', '', ''),
(7, 'BG190-016', '[포뷰트] 헤어 스타일링 2종 세트', '포뷰트', 17900, 0, 0, '컬크림과 스프레이를 함께 쓰는 헤어 스타일링 2종 세트입니다. 자연스러운 결 정돈과 고정력을 함께 챙길 수 있습니다.', 1, CURDATE(), 0, 1, 0, 0, '', '', '');
